const { regular, bold, script, icons } = await loadFonts();
  const { name, phone, address, logo } = brandData;
  const scale = getScale(width, height);

  // 1. Chalkboard / Dark Background Header
  const paint = Skia.Paint();
  paint.setColor(Skia.Color('#1F1F1F'));
  canvas.drawRect({ x: 0, y: 0, width, height: 160 * scale }, paint);

  // 2. Title "TODAY'S SPECIAL"
  paint.setColor(Skia.Color('#FFA500')); // Orange
  const titleFont = script;
  titleFont.setSize(70 * scale);
  drawTextCentered(canvas, "Today's Special", 100 * scale, titleFont, paint, width);

  // 3. Floating Footer for Order Info
  const footerH = 140 * scale;
  paint.setColor(Skia.Color('white'));
  canvas.drawRect({ x: 0, y: height - footerH, width, height: footerH }, paint);

  // 4. Contact Details
  paint.setColor(Skia.Color('black'));
  const contactFont = bold;
  contactFont.setSize(30 * scale);

  // Phone (Left) with Icon
  drawIcon(canvas, 'call', 40 * scale, height - 90 * scale, 35 * scale, paint, icons);
  drawTextLeft(canvas, phone, 90 * scale, height - 60 * scale, contactFont, paint, width - (40 * scale));

  // Address (Right)
  const addrFont = regular;
  addrFont.setSize(26 * scale);
  const addrText = address ? address.substring(0, 25) : name;
  const addrW = addrFont.getTextWidth(addrText);

  drawIcon(canvas, 'restaurant', width - addrW - 90 * scale, height - 90 * scale, 35 * scale, paint, icons);
  drawTextLeft(canvas, addrText, width - addrW - 40 * scale, height - 60 * scale, addrFont, paint, width - (40 * scale));

  // Logo Overlay (Top Left)
  if (logo) {
      const lSize = 100 * scale;
      const { width: lW, height: lH } = getLogoDimensions(logo);
      drawLogo(canvas, logo, 20 * scale, 20 * scale, lSize, lSize * (lH/lW));
  }

  return ["phone", "address", "logoUri"];

const { condensed, bold, icons } = await loadFonts();
  const { name, address } = brandData;
  const scale = getScale(width, height);

  // Circular Badge Bottom Right
  const circleSize = 250 * scale;
  const cx = width - (150 * scale);
  const cy = height - (150 * scale);

  const paint = Skia.Paint();
  paint.setColor(Skia.Color('#3E2723')); // Coffee Brown
  canvas.drawCircle(cx, cy, circleSize / 2, paint);

  // Inner Ring
  paint.setStyle(1); // Stroke
  paint.setStrokeWidth(5 * scale);
  paint.setColor(Skia.Color('#D7CCC8'));
  canvas.drawCircle(cx, cy, (circleSize / 2) - (15*scale), paint);

  // Text inside circle
  paint.setStyle(0); // Fill
  paint.setColor(Skia.Color('white'));
  const font = condensed;
  font.setSize(40 * scale);
  const w1 = font.getTextWidth("FRESH");
  canvas.drawText("FRESH", cx - (w1/2), cy - (20*scale), paint, font);

  const w2 = font.getTextWidth("DAILY");
  canvas.drawText("DAILY", cx - (w2/2), cy + (20*scale), paint, font);

  // Address Bar Bottom Left
  paint.setColor(Skia.Color('white'));
  const barW = width - (200 * scale); // Stop before circle
  canvas.drawRect({x: 0, y: height - 100*scale, width: barW, height: 100*scale}, paint);

  paint.setColor(Skia.Color('#3E2723'));
  const addrFont = bold;
  addrFont.setSize(28 * scale);
  if (address) {
      drawIcon(canvas, 'location', 30*scale, height - 65*scale, 30*scale, paint, icons);
      drawTextLeft(canvas, address, 70*scale, height - 40*scale, addrFont, paint, width - (40 * scale));
  }

  return ["address"];
